我理解了！由于你的数据转换脚本将bbox转换为0-999归一化格式，但可视化时需要转换回像素坐标。我们需要从原始的input JSON中提取图像尺寸信息。

下面是修改后的可视化脚本：

```python
#!/usr/bin/env python3
"""
可视化 LLaMA-Factory 训练数据
检查标注质量和格式是否正确
支持 0-999 归一化的 bbox 坐标
"""
import json
import os
import re
from pathlib import Path
from typing import Dict, List, Any, Tuple
import argparse
from PIL import Image, ImageDraw, ImageFont
from tqdm import tqdm
import random

def load_image_info_from_source(source_json: str) -> Dict[str, Tuple[int, int]]:
    """
    从原始数据源中提取图像尺寸信息

    Args:
        source_json: 原始的 grounding JSON 文件路径

    Returns:
        Dict: {image_path: (width, height)}
    """
    print(f"Loading image info from source: {source_json}...")

    if not os.path.exists(source_json):
        print(f"Warning: Source file not found: {source_json}")
        return {}

    with open(source_json, 'r', encoding='utf-8') as f:
        data = json.load(f)

    # 如果是单个对象，转为列表
    if isinstance(data, dict):
        data = [data]

    image_info_map = {}

    for record in data:
        image_info = record.get("image", {})
        width = image_info.get("width")
        height = image_info.get("height")

        if not width or not height:
            continue

        # 获取图像路径
        image_paths = record.get("image_paths", {})
        original_image = image_paths.get("original_image", "")

        if original_image:
            image_info_map[original_image] = (width, height)

        # 同时保存所有 annotation 的图像路径
        individual_annos = image_paths.get("individual_annotations", [])
        for anno_item in individual_annos:
            box_path = anno_item.get("box_image_path")
            clip_path = anno_item.get("clip_image_path")

            if box_path:
                image_info_map[box_path] = (width, height)
            if clip_path:
                image_info_map[clip_path] = (width, height)

    print(f"Loaded {len(image_info_map)} image size records")
    return image_info_map

def convert_normalized_bbox_to_pixel(
    bbox_999: List[int],
    width: int,
    height: int
) -> List[int]:
    """
    将 0-999 归一化的 bbox 转换回像素坐标

    Args:
        bbox_999: [x1, y1, x2, y2] 0-999 归一化坐标
        width: 图像宽度
        height: 图像高度

    Returns:
        [x1, y1, x2, y2] 像素坐标
    """
    x1_norm, y1_norm, x2_norm, y2_norm = bbox_999

    # 转换回像素坐标
    x1 = int((x1_norm / 999) * width)
    y1 = int((y1_norm / 999) * height)
    x2 = int((x2_norm / 999) * width)
    y2 = int((y2_norm / 999) * height)

    return [x1, y1, x2, y2]

def extract_bbox_from_content(content: str) -> List[int]:
    """从 assistant 回复中提取 bbox（0-999 归一化格式）"""
    try:
        # 尝试解析 JSON
        match = re.search(r'\{.*?"bbox_2d".*?\}', content, re.DOTALL)
        if match:
            data = json.loads(match.group(0))
            bbox = data.get("bbox_2d")
            if bbox and isinstance(bbox, list) and len(bbox) == 4:
                return [int(x) for x in bbox]
    except:
        pass
    return None

def extract_description_from_prompt(content: str) -> str:
    """从 user prompt 中提取描述部分"""
    # 提取 "describes:\n" 和 "\nEnsure" 之间的内容
    match = re.search(r'describes:\n(.*?)\nEnsure', content, re.DOTALL)
    if match:
        return match.group(1).strip()
    return content[:200] + "..."  # 备选：返回前200字符

def get_image_size(image_path: str, image_info_map: Dict[str, Tuple[int, int]]) -> Tuple[int, int]:
    """
    获取图像尺寸（优先从 map 中获取，否则从图像文件读取）

    Args:
        image_path: 图像路径
        image_info_map: 图像尺寸信息字典

    Returns:
        (width, height)
    """
    # 优先从 map 中获取
    if image_path in image_info_map:
        return image_info_map[image_path]

    # 否则尝试从图像文件读取
    if os.path.exists(image_path):
        try:
            with Image.open(image_path) as img:
                return img.size
        except Exception as e:
            print(f"Warning: Cannot read image size from {image_path}: {e}")

    return None, None

def visualize_training_sample(
    sample: Dict[str, Any],
    output_path: str,
    sample_idx: int,
    image_info_map: Dict[str, Tuple[int, int]],
    show_description: bool = True
):
    """
    可视化单个训练样本

    Args:
        sample: LLaMA-Factory 格式的样本
        output_path: 输出路径
        sample_idx: 样本索引
        image_info_map: 图像尺寸信息字典
        show_description: 是否显示描述文本
    """
    # 解析样本
    messages = sample.get("messages", [])
    images = sample.get("images", [])

    if not messages or len(messages) < 2:
        print(f"Warning: Invalid messages in sample {sample_idx}")
        return False

    if not images:
        print(f"Warning: No images in sample {sample_idx}")
        return False

    # 获取图像路径
    image_path = images[0]
    if not os.path.exists(image_path):
        print(f"Warning: Image not found: {image_path}")
        return False

    # 提取 bbox (0-999 归一化格式)
    user_content = messages[0].get("content", "")
    assistant_content = messages[1].get("content", "")

    bbox_999 = extract_bbox_from_content(assistant_content)
    description = extract_description_from_prompt(user_content)

    # 获取图像尺寸
    width, height = get_image_size(image_path, image_info_map)

    if not width or not height:
        print(f"Warning: Cannot get image size for {image_path}")
        return False

    # 将 bbox 转换为像素坐标
    bbox_pixel = None
    if bbox_999:
        bbox_pixel = convert_normalized_bbox_to_pixel(bbox_999, width, height)

    # 加载图像
    try:
        image = Image.open(image_path).convert('RGB')
    except Exception as e:
        print(f"Error loading image {image_path}: {e}")
        return False

    draw = ImageDraw.Draw(image)

    # 加载字体
    try:
        title_font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 32)
        desc_font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 20)
        small_font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 18)
    except:
        title_font = ImageFont.load_default()
        desc_font = ImageFont.load_default()
        small_font = ImageFont.load_default()

    # 绘制 bbox
    if bbox_pixel:
        # 蓝色框表示训练标注
        draw.rectangle(bbox_pixel, outline='#00BFFF', width=6)

        # 在框上方标注
        label_text = f"Training Label"
        y_text_pos = max(bbox_pixel[1] - 40, 10)
        draw.text((bbox_pixel[0], y_text_pos), label_text, fill='#00BFFF', font=title_font)

        # 显示归一化坐标和像素坐标
        coord_text_999 = f"Norm[0-999]: {bbox_999}"
        coord_text_pixel = f"Pixel: {bbox_pixel}"
        y_coord_pos = max(bbox_pixel[1] - 100, 40)
        draw.text((bbox_pixel[0], y_coord_pos), coord_text_999, fill='#00BFFF', font=small_font)
        draw.text((bbox_pixel[0], y_coord_pos + 25), coord_text_pixel, fill='#00BFFF', font=small_font)
    else:
        # 标注为 null
        draw.text((10, 10), "bbox_2d: null", fill='red', font=title_font)

    # 添加信息栏
    if show_description:
        # 计算需要的高度
        desc_lines = []
        max_width = image.width - 40

        # 分割描述文本为多行
        words = description.split()
        current_line = ""
        for word in words:
            test_line = current_line + " " + word if current_line else word
            # 简单估算宽度
            if len(test_line) * 10 < max_width:
                current_line = test_line
            else:
                if current_line:
                    desc_lines.append(current_line)
                current_line = word
        if current_line:
            desc_lines.append(current_line)

        # 限制最多显示5行
        desc_lines = desc_lines[:5]
        if len(desc_lines) == 5 and len(words) > len(" ".join(desc_lines).split()):
            desc_lines[-1] += "..."

        info_height = 140 + len(desc_lines) * 25

        # 创建信息栏
        info_bg = Image.new('RGB', (image.width, info_height), color='#2C3E50')
        info_draw = ImageDraw.Draw(info_bg)

        # 绘制标题
        info_draw.text((20, 15), f"Training Sample #{sample_idx}", fill='white', font=title_font)

        # 绘制图像尺寸信息
        size_text = f"Image Size: {width} x {height}"
        info_draw.text((20, 55), size_text, fill='#3498DB', font=small_font)

        # 绘制描述
        y_offset = 90
        for line in desc_lines:
            info_draw.text((20, y_offset), line, fill='#ECF0F1', font=desc_font)
            y_offset += 25

        # 合并图像
        result = Image.new('RGB', (image.width, image.height + info_height))
        result.paste(info_bg, (0, 0))
        result.paste(image, (0, info_height))
        image = result

    # 保存
    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    image.save(output_path, quality=95)
    return True

def analyze_training_data(
    data_json: str,
    output_dir: str,
    source_json: str = None,
    max_samples: int = None,
    check_mode: str = 'random'
):
    """
    分析训练数据质量

    Args:
        data_json: LLaMA-Factory 格式的训练数据
        output_dir: 输出目录
        source_json: 原始数据源（用于获取图像尺寸）
        max_samples: 最多可视化多少个样本
        check_mode: 检查模式 ('random', 'first', 'all')
    """
    print(f"Loading training data from {data_json}...")
    with open(data_json, 'r', encoding='utf-8') as f:
        data = json.load(f)

    print(f"Total samples: {len(data)}")

    # 加载图像尺寸信息
    image_info_map = {}
    if source_json:
        image_info_map = load_image_info_from_source(source_json)
    else:
        print("Warning: No source JSON provided, will try to read image sizes from files")

    # 统计分析
    stats = {
        'total': len(data),
        'with_bbox': 0,
        'null_bbox': 0,
        'invalid_format': 0,
        'missing_images': 0,
        'missing_size_info': 0,
        'bbox_coords_999': [],  # 归一化坐标
        'bbox_coords_pixel': []  # 像素坐标
    }

    # 检查每个样本
    print("\nAnalyzing data quality...")
    for i, sample in enumerate(tqdm(data, desc="Checking")):
        messages = sample.get("messages", [])
        images = sample.get("images", [])

        # 检查格式
        if len(messages) < 2:
            stats['invalid_format'] += 1
            continue

        if not images:
            stats['missing_images'] += 1
            continue

        image_path = images[0]

        # 检查图像是否存在
        if not os.path.exists(image_path):
            stats['missing_images'] += 1
            continue

        # 检查是否有尺寸信息
        width, height = get_image_size(image_path, image_info_map)
        if not width or not height:
            stats['missing_size_info'] += 1

        # 提取 bbox
        assistant_content = messages[1].get("content", "")
        bbox_999 = extract_bbox_from_content(assistant_content)

        if bbox_999:
            stats['with_bbox'] += 1
            stats['bbox_coords_999'].append(bbox_999)

            # 如果有尺寸信息，转换为像素坐标
            if width and height:
                bbox_pixel = convert_normalized_bbox_to_pixel(bbox_999, width, height)
                stats['bbox_coords_pixel'].append(bbox_pixel)
        else:
            stats['null_bbox'] += 1

    # 打印统计
    print("\n" + "="*60)
    print("DATA QUALITY REPORT")
    print("="*60)
    print(f"Total samples: {stats['total']}")
    print(f"Valid samples with bbox: {stats['with_bbox']} ({stats['with_bbox']/stats['total']*100:.1f}%)")
    print(f"Samples with null bbox: {stats['null_bbox']} ({stats['null_bbox']/stats['total']*100:.1f}%)")
    print(f"Invalid format: {stats['invalid_format']}")
    print(f"Missing images: {stats['missing_images']}")
    print(f"Missing size info: {stats['missing_size_info']}")

    # bbox 坐标范围分析 (0-999 归一化)
    if stats['bbox_coords_999']:
        import numpy as np
        coords = np.array(stats['bbox_coords_999'])
        print("\n📏 BBox Coordinate Statistics (0-999 Normalized):")
        print(f"  x1 range: [{coords[:, 0].min():.1f}, {coords[:, 0].max():.1f}]")
        print(f"  y1 range: [{coords[:, 1].min():.1f}, {coords[:, 1].max():.1f}]")
        print(f"  x2 range: [{coords[:, 2].min():.1f}, {coords[:, 2].max():.1f}]")
        print(f"  y2 range: [{coords[:, 3].min():.1f}, {coords[:, 3].max():.1f}]")

        width_999 = coords[:, 2] - coords[:, 0]
        height_999 = coords[:, 3] - coords[:, 1]
        print(f"  Width range: [{width_999.min():.1f}, {width_999.max():.1f}]")
        print(f"  Height range: [{height_999.min():.1f}, {height_999.max():.1f}]")

        # 检查是否有异常坐标
        if (width_999 <= 0).any() or (height_999 <= 0).any():
            print("  ⚠️  WARNING: Found invalid bboxes with negative width/height!")
            invalid_count = ((width_999 <= 0) | (height_999 <= 0)).sum()
            print(f"     Invalid count: {invalid_count}")

        # 检查是否超出 0-999 范围
        if (coords < 0).any() or (coords > 999).any():
            print("  ⚠️  WARNING: Found coordinates outside [0, 999] range!")
            out_of_range = ((coords < 0) | (coords > 999)).any(axis=1).sum()
            print(f"     Out of range count: {out_of_range}")

    # 像素坐标统计
    if stats['bbox_coords_pixel']:
        import numpy as np
        coords_pixel = np.array(stats['bbox_coords_pixel'])
        print("\n🖼️  BBox Coordinate Statistics (Pixel):")
        print(f"  x1 range: [{coords_pixel[:, 0].min()}, {coords_pixel[:, 0].max()}]")
        print(f"  y1 range: [{coords_pixel[:, 1].min()}, {coords_pixel[:, 1].max()}]")
        print(f"  x2 range: [{coords_pixel[:, 2].min()}, {coords_pixel[:, 2].max()}]")
        print(f"  y2 range: [{coords_pixel[:, 3].min()}, {coords_pixel[:, 3].max()}]")

    print("="*60)

    # 选择要可视化的样本
    if check_mode == 'random':
        num_vis = min(max_samples or 50, len(data))
        random.seed(42)
        samples_to_vis = random.sample(range(len(data)), num_vis)
    elif check_mode == 'first':
        num_vis = min(max_samples or 50, len(data))
        samples_to_vis = range(num_vis)
    else:  # 'all'
        samples_to_vis = range(len(data))

    print(f"\nVisualizing {len(samples_to_vis)} samples...")

    # 可视化样本
    os.makedirs(output_dir, exist_ok=True)
    success_count = 0

    for idx in tqdm(samples_to_vis, desc="Visualizing"):
        sample = data[idx]

        # 提取原始图像文件名
        images = sample.get("images", [])
        if images:
            img_basename = os.path.basename(images[0])
            img_name = os.path.splitext(img_basename)[0]
            output_filename = f"train_{idx:05d}_{img_name}.jpg"
        else:
            output_filename = f"train_{idx:05d}_noimage.jpg"

        output_path = os.path.join(output_dir, output_filename)

        success = visualize_training_sample(
            sample=sample,
            output_path=output_path,
            sample_idx=idx,
            image_info_map=image_info_map,
            show_description=True
        )

        if success:
            success_count += 1

    print(f"\n✓ Visualization complete!")
    print(f"  Success: {success_count}/{len(samples_to_vis)}")
    print(f"  Output: {output_dir}")

    # 生成 HTML
    create_html_gallery(output_dir, data_json, stats)

def create_html_gallery(output_dir: str, data_json: str, stats: Dict):
    """创建 HTML 浏览页面"""
    image_files = sorted([f for f in os.listdir(output_dir) if f.endswith('.jpg')])

    html_content = f"""
