        <meta charset="utf-8">
        <style>
            body {{
                font-family: Arial, sans-serif;
                margin: 0;
                padding: 20px;
                background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            }}
            .container {{
                max-width: 1400px;
                margin: 0 auto;
                background-color: white;
                border-radius: 12px;
                padding: 30px;
            }}
            h1 {{
                color: #2C3E50;
                text-align: center;
            }}
            .stats {{
                background-color: #ECF0F1;
                padding: 20px;
                border-radius: 8px;
                margin-bottom: 30px;
            }}
            .stat-item {{
                display: inline-block;
                margin-right: 30px;
                margin-bottom: 10px;
                font-size: 16px;
            }}
            .stat-value {{
                font-weight: bold;
                color: #3498DB;
            }}
            .warning {{
                background-color: #FFF3CD;
                border-left: 4px solid #FFC107;
                padding: 15px;
                margin-bottom: 20px;
            }}
            .info {{
                background-color: #D1ECF1;
                border-left: 4px solid #17A2B8;
                padding: 15px;
                margin-bottom: 20px;
            }}
            .gallery {{
                display: grid;
                grid-template-columns: repeat(auto-fill, minmax(500px, 1fr));
                gap: 25px;
            }}
            .item {{
                background-color: white;
                border-radius: 8px;
                padding: 10px;
                box-shadow: 0 2px 8px rgba(0,0,0,0.1);
            }}
            .item img {{
                width: 100%;
                height: auto;
                border-radius: 4px;
                cursor: pointer;
            }}
            .item:hover {{
                box-shadow: 0 4px 16px rgba(0,0,0,0.2);
            }}
        </style>
    </head>
    <body>
        <div class="container">
            <h1>🎓 Training Data Visualization (0-999 Normalized BBox)</h1>

            <div class="info">
                <strong>ℹ️ Coordinate Format:</strong>
                <p>BBoxes are stored in 0-999 normalized format and converted to pixel coordinates for visualization.</p>
            </div>

            <div class="stats">
                <h2>Data Statistics</h2>
                <div class="stat-item">
                    <span class="stat-label">Total Samples:</span>
                    <span class="stat-value">{stats['total']}</span>
                </div>
                <div class="stat-item">
                    <span class="stat-label">With BBox:</span>
                    <span class="stat-value">{stats['with_bbox']} ({stats['with_bbox']/stats['total']*100:.1f}%)</span>
                </div>
                <div class="stat-item">
                    <span class="stat-label">Null BBox:</span>
                    <span class="stat-value">{stats['null_bbox']} ({stats['null_bbox']/stats['total']*100:.1f}%)</span>
                </div>
                <div class="stat-item">
                    <span class="stat-label">Missing Images:</span>
                    <span class="stat-value">{stats['missing_images']}</span>
                </div>
                <div class="stat-item">
                    <span class="stat-label">Missing Size Info:</span>
                    <span class="stat-value">{stats['missing_size_info']}</span>
                </div>
            </div>
    """

    # 添加警告（如果有问题）
    if stats['missing_images'] > 0 or stats['invalid_format'] > 0 or stats['missing_size_info'] > 0:
        html_content += f"""
            <div class="warning">
                <strong>⚠️ Data Quality Issues Detected:</strong>
                <ul>
        """
        if stats['missing_images'] > 0:
            html_content += f"<li>Missing images: {stats['missing_images']} samples</li>"
        if stats['invalid_format'] > 0:
            html_content += f"<li>Invalid format: {stats['invalid_format']} samples</li>"
        if stats['missing_size_info'] > 0:
            html_content += f"<li>Missing size info: {stats['missing_size_info']} samples</li>"
        html_content += """
                </ul>
            </div>
        """

    html_content += f"""
            <h2>Sample Gallery ({len(image_files)} images)</h2>
            <div class="gallery">
    """

    for img_file in image_files:
        html_content += f"""
            <div class="item">
                <img src="{img_file}" alt="{img_file}" onclick="window.open('{img_file}', '_blank')">
            </div>
        """

    html_content += """
            </div>
        </div>
    </body>
    </html>
    """

    html_path = os.path.join(output_dir, 'index.html')
    with open(html_path, 'w', encoding='utf-8') as f:
        f.write(html_content)

    print(f"\n✓ HTML gallery created: {html_path}")
    print(f"  Open: file://{os.path.abspath(html_path)}")

def main():
    parser = argparse.ArgumentParser(
        description="Visualize LLaMA-Factory training data with 0-999 normalized bbox"
    )
    parser.add_argument("--data", type=str, required=True,
                        help="Path to LLaMA-Factory training JSON")
    parser.add_argument("--input", type=str, default=None,
                        help="Path to source JSON (for image size info)")
    parser.add_argument("--output", type=str, default="train_vis",
                        help="Output directory")
    parser.add_argument("--max-samples", type=int, default=50,
                        help="Maximum samples to visualize")
    parser.add_argument("--mode", type=str, choices=['random', 'first', 'all'], default='random',
                        help="Sampling mode")

    args = parser.parse_args()

    analyze_training_data(
        data_json=args.data,
        output_dir=args.output,
        source_json=args.input,
        max_samples=args.max_samples,
        check_mode=args.mode
    )

if __name__ == "__main__":
    main()

